mapper.update:
UPDATE UB_NOTICEBOARD
SET board_click = board_click + 1
WHERE noticeboard_number = #{noticeBoardNumber}

mapper.select:

SELECT * FROM (
	SELECT ROWNUM AS rnum, subquery.*
	FROM (
		SELECT  b.noticeboard_number, b.board_title, 
			b.board_content, b.board_date, b.board_click
		FROM UB_NOTICEBOARD b
		ORDER BY b.board_date DESC
	) subquery
) WHERE rnum BETWEEN #{startRow} AND #{endRow}
